Test file: src/claim-office.spec.ts
Failing test: "CLI reads JSON from stdin and writes JSON {results: [...]} to stdout"
Expected: scenario {customer, steps:[]} produces {results:[]}
Implementation file: src/cli.ts

Implement minimal CLI:
- Read all of stdin
- Parse JSON
- For each step: if op="quote", call quote(); if op="claim", call claim() with the referenced policy
- Output {results: [...]}

For now, minimal: handle empty steps. Output {results:[]}.

Use process.stdin to read all input then parse and write JSON to stdout.

Sample code:
```ts
import { quote, claim } from "./claim-office.js";
let data = "";
process.stdin.on("data", chunk => data += chunk);
process.stdin.on("end", () => {
  const scenario = JSON.parse(data);
  const results: any[] = [];
  const policies: any[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const q = quote({customer: scenario.customer, items: step.items});
      results.push({premium: q.premium});
      policies.push({items: step.items, remainingCap: undefined});
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      const c = claim({items: policy.items, damages: step.incident.damages, remainingCap: policy.remainingCap});
      policy.remainingCap = c.remainingCap;
      results.push({payout: c.payout, remainingCap: c.remainingCap});
    }
  }
  process.stdout.write(JSON.stringify({results}));
});
```

